const express = require('express');

const app = express();
app.use(express.json());

const players = new Map();

function getPlayer(playerId) {
  if (!players.has(playerId)) {
    players.set(playerId, {
      playerId,
      coins: 0,
      gems: 0,
      completedLevels: {},
      claimedRewards: {}
    });
  }
  return players.get(playerId);
}

function calculateLevelReward(score, time) {
  let coins = Math.max(10, Math.floor(score / 10));
  let gems = 0;

  if (score >= 1000) gems += 5;
  else if (score >= 500) gems += 2;

  if (time <= 60) {
    coins += 50;
    gems += 1;
  } else if (time <= 120) {
    coins += 20;
  }

  return { coins, gems };
}

app.post('/level/complete', (req, res) => {
  const { playerId, levelId, score, time } = req.body;

  if (!playerId || levelId === undefined || score === undefined || time === undefined) {
    return res.status(400).json({ error: 'playerId, levelId, score, and time are required' });
  }

  if (typeof score !== 'number' || typeof time !== 'number' || score < 0 || time < 0) {
    return res.status(400).json({ error: 'score and time must be non-negative numbers' });
  }

  const player = getPlayer(playerId);
  const reward = calculateLevelReward(score, time);

  player.coins += reward.coins;
  player.gems += reward.gems;
  player.completedLevels[levelId] = {
    score,
    time,
    completedAt: new Date().toISOString(),
    reward
  };

  res.json({
    success: true,
    levelId,
    submitted: { score, time },
    reward,
    balances: {
      coins: player.coins,
      gems: player.gems
    }
  });
});

app.post('/reward/claim', (req, res) => {
  const { playerId, rewardId, score, time } = req.body;

  if (!playerId || !rewardId || score === undefined || time === undefined) {
    return res.status(400).json({ error: 'playerId, rewardId, score, and time are required' });
  }

  if (typeof score !== 'number' || typeof time !== 'number' || score < 0 || time < 0) {
    return res.status(400).json({ error: 'score and time must be non-negative numbers' });
  }

  const player = getPlayer(playerId);

  if (player.claimedRewards[rewardId]) {
    return res.status(409).json({ error: 'Reward already claimed' });
  }

  const reward = calculateLevelReward(score, time);

  player.coins += reward.coins;
  player.gems += reward.gems;
  player.claimedRewards[rewardId] = {
    claimedAt: new Date().toISOString(),
    basedOn: { score, time },
    reward
  };

  res.json({
    success: true,
    rewardId,
    reward,
    balances: {
      coins: player.coins,
      gems: player.gems
    }
  });
});

app.get('/player/:playerId', (req, res) => {
  const player = getPlayer(req.params.playerId);
  res.json(player);
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Game API listening on port ${port}`);
});